use std::cmp::Ordering;

fn get_longest_slice<'a>(s1: &'a str, s2: &'a str) -> &'a str {
    match s1.len().cmp(&s2.len()) {
        Ordering::Greater => s1,
        Ordering::Less => s2,
        Ordering::Equal => s1,
    }
}

fn main() {
    let slice_a = "hello";
    let slice_b = "world";
    let result = get_longest_slice(slice_a, slice_b);
    println!("The longest slice is: {}", result);

    let short_str = "hi";
    let long_str = "rustlang";
    let result2 = get_longest_slice(short_str, long_str);
    println!("The second longest slice is: {}", result2);
}

